#include <stdio.h>
#include <math.h>
int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    double minX = 1e9, minY = 1e9, maxX = -1e9, maxY = -1e9;
    for (int i = 0; i < N; i++) {
        double x, y;
        scanf("%lf %lf", &x, &y);
        minX = fmin(minX, x);
        minY = fmin(minY, y);
        maxX = fmax(maxX, x);
        maxY = fmax(maxY, y);
    }
    double width = maxX - minX;
    double height = maxY - minY;
    double perimeter = 2 * (width + height);
    printf("%.9f\n", perimeter);
    return 0;
}

