    double minX = 1e9, minY = 1e9, maxX = -1e9, maxY = -1e9;
    for (int i = 0; i < N; i++) {
        double x, y;
        cin >> x >> y;
        minX = min(minX, x);
        minY = min(minY, y);
        maxX = max(maxX, x);
        maxY = max(maxY, y);
    }
    double width = maxX - minX;
    double height = maxY - minY;
    double perimeter = 2 * (width + height);
    cout << fixed << setprecision(9) << perimeter << endl;
    return 0;
}

